     1→//! Error recovery utilities for FORGE.
     2→//!
     3→//! This module provides retry logic, exponential backoff, and graceful
     4→//! degradation strategies for handling transient errors.
     5→//!
     6→//! ## Features
     7→//!
     8→//! - **Exponential backoff**: Retry operations with increasing delays
     9→//! - **Jitter**: Randomize retry intervals to prevent thundering herd
    10→//! - **Configurable limits**: Control max retries and total timeout
    11→//! - **Error classification**: Determine if errors are retryable
    12→//!
    13→//! ## Example
    14→//!
    15→//! ```no_run
    16→//! use forge_core::recovery::{retry_with_backoff, RetryConfig};
    17→//! use std::time::Duration;
    18→//!
    19→//! let config = RetryConfig {
    20→//!     max_retries: 3,
    21→//!     initial_delay: Duration::from_millis(100),
    22→//!     max_delay: Duration::from_secs(5),
    23→//!     multiplier: 2.0,
    24→//! };
    25→//!
    26→//! let result = retry_with_backoff(config, || {
    27→//!     // Operation that might fail transiently
    28→//!     some_network_call()
    29→//! });
    30→//! ```
    31→
    32→use std::future::Future;
    33→use std::thread;
    34→use std::time::Duration;
    35→use tracing::{debug, info, warn};
    36→use rand::Rng;
    37→
    38→/// Configuration for retry behavior with exponential backoff.
    39→#[derive(Debug, Clone)]
    40→pub struct RetryConfig {
    41→    /// Maximum number of retry attempts.
    42→    pub max_retries: u32,
    43→    /// Initial delay before first retry.
    44→    pub initial_delay: Duration,
    45→    /// Maximum delay between retries (caps exponential growth).
    46→    pub max_delay: Duration,
    47→    /// Multiplier for exponential backoff (e.g., 2.0 doubles each time).
    48→    pub multiplier: f64,
    49→}
    50→
    51→impl Default for RetryConfig {
    52→    fn default() -> Self {
    53→        Self {
    54→            max_retries: 3,
    55→            initial_delay: Duration::from_millis(100),
    56→            max_delay: Duration::from_secs(30),
    57→            multiplier: 2.0,
    58→        }
    59→    }
    60→}
    61→
    62→impl RetryConfig {
    63→    /// Create a config for database operations (aggressive retries).
    64→    pub fn for_database() -> Self {
    65→        Self {
    66→            max_retries: 5,
    67→            initial_delay: Duration::from_millis(50),
    68→            max_delay: Duration::from_secs(5),
    69→            multiplier: 1.5,
    70→        }
    71→    }
    72→
    73→    /// Create a config for network operations (moderate retries).
    74→    pub fn for_network() -> Self {
    75→        Self {
    76→            max_retries: 3,
    77→            initial_delay: Duration::from_millis(500),
    78→            max_delay: Duration::from_secs(30),
    79→            multiplier: 2.0,
    80→        }
    81→    }
    82→
    83→    /// Create a config for API rate limits (patient retries).
    84→    pub fn for_rate_limit() -> Self {
    85→        Self {
    86→            max_retries: 5,
    87→            initial_delay: Duration::from_secs(1),
    88→            max_delay: Duration::from_secs(60),
    89→            multiplier: 2.0,
    90→        }
    91→    }
    92→
    93→    /// Create a config for worker operations (quick retries).
    94→    pub fn for_worker() -> Self {
    95→        Self {
    96→            max_retries: 2,
    97→            initial_delay: Duration::from_millis(100),
    98→            max_delay: Duration::from_secs(2),
    99→            multiplier: 2.0,
   100→        }
   101→    }
   102→
   103→    /// Calculate delay for a given attempt number with jitter.
   104→    pub fn delay_for_attempt(&self, attempt: u32) -> Duration {
   105→        let base_delay = self.initial_delay.as_secs_f64()
   106→            * self.multiplier.powi(attempt as i32);
   107→
   108→        let capped_delay = base_delay.min(self.max_delay.as_secs_f64());
   109→
   110→        // Add jitter (±25% of delay)
   111→        let jitter_range = capped_delay * 0.25;
   112→        let mut rng = rand::rng();
   113→        let jitter = rng.random_range(-jitter_range..jitter_range);
   114→        let final_delay = (capped_delay + jitter).max(0.0).min(self.max_delay.as_secs_f64());
   115→
   116→        Duration::from_secs_f64(final_delay)
   117→    }
   118→}
   119→
   120→/// Result of a retry operation with metadata about the attempts.
   121→#[derive(Debug)]
   122→pub struct RetryResult<T> {
   123→    /// The final result (success or last error).
   124→    pub result: T,
   125→    /// Number of attempts made.
   126→    pub attempts: u32,
   127→    /// Total time spent retrying.
   128→    pub total_duration: Duration,
   129→}
   130→
   131→/// Retry a synchronous operation with exponential backoff.
   132→///
   133→/// Returns the result of the operation if successful, or the last error
   134→/// if all retries are exhausted.
   135→pub fn retry_with_backoff<T, E, F>(
   136→    config: RetryConfig,
   137→    mut operation: F,
   138→) -> RetryResult<Result<T, E>>
   139→where
   140→    F: FnMut() -> Result<T, E>,
   141→    E: std::fmt::Debug,
   142→{
   143→    let start = std::time::Instant::now();
   144→    let mut attempts = 0;
   145→    let mut last_error: Option<E> = None;
   146→
   147→    loop {
   148→        attempts += 1;
   149→
   150→        match operation() {
   151→            Ok(value) => {
   152→                if attempts > 1 {
   153→                    info!(
   154→                        attempts,
   155→                        total_ms = start.elapsed().as_millis(),
   156→                        "Operation succeeded after retry"
   157→                    );
   158→                }
   159→                return RetryResult {
   160→                    result: Ok(value),
   161→                    attempts,
   162→                    total_duration: start.elapsed(),
   163→                };
   164→            }
   165→            Err(e) => {
   166→                last_error = Some(e);
   167→
   168→                if attempts > config.max_retries {
   169→                    warn!(
   170→                        attempts,
   171→                        max_retries = config.max_retries,
   172→                        total_ms = start.elapsed().as_millis(),
   173→                        "Operation failed after all retries"
   174→                    );
   175→                    return RetryResult {
   176→                        result: Err(last_error.unwrap()),
   177→                        attempts,
   178→                        total_duration: start.elapsed(),
   179→                    };
   180→                }
   181→
   182→                let delay = config.delay_for_attempt(attempts - 1);
   183→                debug!(
   184→                    attempt = attempts,
   185→                    delay_ms = delay.as_millis(),
   186→                    "Operation failed, retrying with backoff"
   187→                );
   188→
   189→                thread::sleep(delay);
   190→            }
   191→        }
   192→    }
   193→}
   194→
   195→/// Retry an async operation with exponential backoff.
   196→///
   197→/// Returns the result of the operation if successful, or the last error
   198→/// if all retries are exhausted.
   199→pub async fn retry_with_backoff_async<T, E, F, Fut>(
   200→    config: RetryConfig,
   201→    mut operation: F,
   202→) -> RetryResult<Result<T, E>>
   203→where
   204→    F: FnMut() -> Fut,
   205→    Fut: Future<Output = Result<T, E>>,
   206→    E: std::fmt::Debug,
   207→{
   208→    let start = std::time::Instant::now();
   209→    let mut attempts = 0;
   210→    let mut last_error: Option<E> = None;
   211→
   212→    loop {
   213→        attempts += 1;
   214→
   215→        match operation().await {
   216→            Ok(value) => {
   217→                if attempts > 1 {
   218→                    info!(
   219→                        attempts,
   220→                        total_ms = start.elapsed().as_millis(),
   221→                        "Async operation succeeded after retry"
   222→                    );
   223→                }
   224→                return RetryResult {
   225→                    result: Ok(value),
   226→                    attempts,
   227→                    total_duration: start.elapsed(),
   228→                };
   229→            }
   230→            Err(e) => {
   231→                last_error = Some(e);
   232→
   233→                if attempts > config.max_retries {
   234→                    warn!(
   235→                        attempts,
   236→                        max_retries = config.max_retries,
   237→                        total_ms = start.elapsed().as_millis(),
   238→                        "Async operation failed after all retries"
   239→                    );
   240→                    return RetryResult {
   241→                        result: Err(last_error.unwrap()),
   242→                        attempts,
   243→                        total_duration: start.elapsed(),
   244→                    };
   245→                }
   246→
   247→                let delay = config.delay_for_attempt(attempts - 1);
   248→                debug!(
   249→                    attempt = attempts,
   250→                    delay_ms = delay.as_millis(),
   251→                    "Async operation failed, retrying with backoff"
   252→                );
   253→
   254→                tokio::time::sleep(delay).await;
   255→            }
   256→        }
   257→    }
   258→}
   259→
   260→/// Trait for determining if an error is retryable.
   261→pub trait Retryable {
   262→    /// Returns true if the operation that caused this error should be retried.
   263→    fn is_retryable(&self) -> bool;
   264→}
   265→
   266→/// Error recovery action recommendation.
   267→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
   268→pub enum RecoveryAction {
   269→    /// Retry the operation immediately.
   270→    RetryNow,
   271→    /// Retry after a delay (backoff).
   272→    RetryWithBackoff,
   273→    /// Fall back to a default value or cached data.
   274→    UseFallback,
   275→    /// Log the error and continue (non-critical).
   276→    LogAndContinue,
   277→    /// Show error to user and wait for input.
   278→    NotifyUser,
   279→    /// The error is fatal, cannot recover.
   280→    Fatal,
   281→}
   282→
   283→impl RecoveryAction {
   284→    /// Determine the appropriate recovery action from an error message.
   285→    pub fn from_error_message(error: &str) -> Self {
   286→        let error_lower = error.to_lowercase();
   287→
   288→        // Database lock errors - always retry
   289→        if error_lower.contains("database is locked")
   290→            || error_lower.contains("sqlalchemy.exc.operationalerror")
   291→            || error_lower.contains("sqlite_busy")
   292→            || error_lower.contains("sqlite_locked")
   293→        {
   294→            return Self::RetryWithBackoff;
   295→        }
   296→
   297→        // Network/timeout errors - retry
   298→        if error_lower.contains("timeout")
   299→            || error_lower.contains("connection refused")
   300→            || error_lower.contains("connection reset")
   301→            || error_lower.contains("network")
   302→            || error_lower.contains("broken pipe")
   303→        {
   304→            return Self::RetryWithBackoff;
   305→        }
   306→
   307→        // Rate limiting - wait and retry
   308→        if error_lower.contains("rate limit")
   309→            || error_lower.contains("too many requests")
   310→            || error_lower.contains("429")
   311→        {
   312→            return Self::RetryWithBackoff;
   313→        }
   314→
   315→        // Server errors - retry (might be temporary)
   316→        if error_lower.contains("500")
   317→            || error_lower.contains("502")
   318→            || error_lower.contains("503")
   319→            || error_lower.contains("504")
   320→            || error_lower.contains("internal server error")
   321→            || error_lower.contains("bad gateway")
   322→            || error_lower.contains("service unavailable")
   323→            || error_lower.contains("gateway timeout")
   324→        {
   325→            return Self::RetryWithBackoff;
   326→        }
   327→
   328→        // Config errors - use defaults
   329→        if error_lower.contains("config")
   330→            && (error_lower.contains("not found") || error_lower.contains("missing"))
   331→        {
   332→            return Self::UseFallback;
   333→        }
   334→
   335→        // Invalid config syntax - notify user
   336→        if error_lower.contains("parse error")
   337→            || error_lower.contains("invalid yaml")
   338→            || error_lower.contains("invalid json")
   339→            || error_lower.contains("syntax error")
   340→        {
   341→            return Self::NotifyUser;
   342→        }
   343→
   344→        // Permission errors - notify user
   345→        if error_lower.contains("permission denied")
   346→            || error_lower.contains("access denied")
   347→            || error_lower.contains("forbidden")
   348→            || error_lower.contains("unauthorized")
   349→        {
   350→            return Self::NotifyUser;
   351→        }
   352→
   353→        // Not found errors - log and continue
   354→        if error_lower.contains("not found") || error_lower.contains("does not exist") {
   355→            return Self::LogAndContinue;
   356→        }
   357→
   358→        // Default: notify user
   359→        Self::NotifyUser
   360→    }
   361→}
   362→
   363→/// User-friendly error message generator.
   364→pub fn friendly_error_message(error: &str) -> String {
   365→    let error_lower = error.to_lowercase();
   366→
   367→    // Database errors
   368→    if error_lower.contains("database is locked") {
   369→        return "The database is busy. FORGE will automatically retry shortly.".to_string();
   370→    }
   371→
   372→    // Network errors
   373→    if error_lower.contains("timeout") || error_lower.contains("connection") {
   374→        return "Network connection issue. Check your internet and try again.".to_string();
   375→    }
   376→
   377→    // Rate limiting
   378→    if error_lower.contains("rate limit") || error_lower.contains("429") {
   379→        return "Too many requests. Please wait a moment before trying again.".to_string();
   380→    }
   381→
   382→    // Config errors
   383→    if error_lower.contains("config") && error_lower.contains("not found") {
   384→        return "Configuration file not found. Using default settings.".to_string();
   385→    }
   386→
   387→    // Auth errors
   388→    if error_lower.contains("unauthorized") || error_lower.contains("api key") {
   389→        return "Authentication failed. Check your API key configuration.".to_string();
   390→    }
   391→
   392→    // Permission errors
   393→    if error_lower.contains("permission denied") {
   394→        return "Permission denied. Check file permissions.".to_string();
   395→    }
   396→
   397→    // Generic fallback
   398→    format!("An error occurred: {}", error)
   399→}
   400→
   401→#[cfg(test)]
   402→mod tests {
   403→    use super::*;
   404→
   405→    #[test]
   406→    fn test_retry_config_delay_calculation() {
   407→        let config = RetryConfig::default();
   408→
   409→        // First attempt should be close to initial delay
   410→        let d1 = config.delay_for_attempt(0);
   411→        assert!(d1.as_millis() >= 50 && d1.as_millis() <= 200);
   412→
   413→        // Second attempt should be roughly double
   414→        let d2 = config.delay_for_attempt(1);
   415→        assert!(d2.as_millis() >= 150 && d2.as_millis() <= 500);
   416→
   417→        // High attempts should cap at max_delay (with small epsilon for floating point)
   418→        let d10 = config.delay_for_attempt(100);
   419→        assert!(d10 <= config.max_delay + Duration::from_millis(1));
   420→    }
   421→
   422→    #[test]
   423→    fn test_retry_success_first_try() {
   424→        let config = RetryConfig::default();
   425→        let mut call_count = 0;
   426→
   427→        let result = retry_with_backoff(config, || {
   428→            call_count += 1;
   429→            Ok::<i32, &str>(42)
   430→        });
   431→
   432→        assert_eq!(result.result, Ok(42));
   433→        assert_eq!(result.attempts, 1);
   434→        assert_eq!(call_count, 1);
   435→    }
   436→
   437→    #[test]
   438→    fn test_retry_success_after_failure() {
   439→        let config = RetryConfig {
   440→            max_retries: 3,
   441→            initial_delay: Duration::from_millis(1),
   442→            max_delay: Duration::from_millis(10),
   443→            multiplier: 1.0,
   444→        };
   445→        let mut call_count = 0;
   446→
   447→        let result = retry_with_backoff(config, || {
   448→            call_count += 1;
   449→            if call_count < 3 {
   450→                Err("temporary error")
   451→            } else {
   452→                Ok::<i32, &str>(42)
   453→            }
   454→        });
   455→
   456→        assert_eq!(result.result, Ok(42));
   457→        assert_eq!(result.attempts, 3);
   458→    }
   459→
   460→    #[test]
   461→    fn test_retry_exhausted() {
   462→        let config = RetryConfig {
   463→            max_retries: 2,
   464→            initial_delay: Duration::from_millis(1),
   465→            max_delay: Duration::from_millis(10),
   466→            multiplier: 1.0,
   467→        };
   468→        let mut call_count = 0;
   469→
   470→        let result = retry_with_backoff(config, || {
   471→            call_count += 1;
   472→            Err::<i32, &str>("persistent error")
   473→        });
   474→
   475→        assert!(result.result.is_err());
   476→        assert_eq!(result.attempts, 3); // 1 initial + 2 retries
   477→    }
