     1→//! Self-update functionality for FORGE binary.
     2→//!
     3→//! This module provides atomic self-update from GitHub releases:
     4→//! 1. Checks GitHub releases API for latest version
     5→//! 2. Compares with current version (semver)
     6→//! 3. Downloads the appropriate binary for the platform
     7→//! 4. Atomically swaps the running binary
     8→//!
     9→//! # Usage
    10→//!
    11→//! ```no_run
    12→//! use forge_core::self_update::{check_for_update, perform_update, UpdateStatus};
    13→//!
    14→//! // Check for updates
    15→//! let status = check_for_update("0.1.9").await?;
    16→//! match status {
    17→//!     UpdateStatus::UpToDate => println!("Already running latest version"),
    18→//!     UpdateStatus::Available { current, latest, download_url, asset_size } => {
    19→//!         println!("Update available: {} -> {}", current, latest);
    20→//!         perform_update(&download_url, asset_size, |progress| {
    21→//!             println!("Downloaded {}%", progress.percent);
    22→//!         }).await?;
    23→//!     }
    24→//! }
    25→//! ```
    26→
    27→use std::env;
    28→use std::fs;
    29→use std::io::{Read, Write};
    30→use std::os::unix::fs::PermissionsExt;
    31→use std::path::{Path, PathBuf};
    32→use std::sync::mpsc::Sender;
    33→use std::time::Duration;
    34→
    35→#[allow(unused_imports)] // Used implicitly by reqwest Response::chunk()
    36→use futures_util::StreamExt;
    37→use serde::Deserialize;
    38→use tracing::{debug, error, info, warn};
    39→
    40→use crate::ForgeError;
    41→
    42→/// GitHub API URL for latest release
    43→const GITHUB_RELEASES_API: &str = "https://api.github.com/repos/jedarden/forge/releases/latest";
    44→
    45→/// User agent for GitHub API requests
    46→const USER_AGENT: &str = concat!("forge/", env!("CARGO_PKG_VERSION"));
    47→
    48→/// HTTP client timeout for API requests
    49→const API_TIMEOUT_SECS: u64 = 10;
    50→
    51→/// HTTP client timeout for downloads
    52→const DOWNLOAD_TIMEOUT_SECS: u64 = 300;
    53→
    54→/// Status of an update check.
    55→#[derive(Debug, Clone)]
    56→pub enum UpdateStatus {
    57→    /// Already running the latest version
    58→    UpToDate,
    59→    /// Update available with download details
    60→    Available {
    61→        /// Current version
    62→        current: String,
    63→        /// Latest available version
    64→        latest: String,
    65→        /// URL to download the binary
    66→        download_url: String,
    67→        /// Size of the asset in bytes
    68→        asset_size: u64,
    69→    },
    70→}
    71→
    72→/// Progress information for download operations.
    73→#[derive(Debug, Clone)]
    74→pub struct DownloadProgress {
    75→    /// Bytes downloaded so far
    76→    pub downloaded: u64,
    77→    /// Total bytes to download
    78→    pub total: u64,
    79→    /// Percentage complete (0-100)
    80→    pub percent: u8,
    81→}
    82→
    83→/// Result of a self-update operation.
    84→#[derive(Debug, Clone)]
    85→pub enum UpdateResult {
    86→    /// Update completed successfully
    87→    Success {
    88→        /// Previous version
    89→        old_version: String,
    90→        /// New version
    91→        new_version: String,
    92→    },
    93→    /// Update failed with error message
    94→    Failed(String),
    95→    /// Already up to date
    96→    AlreadyUpToDate,
    97→}
    98→
    99→/// GitHub release asset information.
   100→#[derive(Debug, Deserialize)]
   101→struct GitHubAsset {
   102→    name: String,
   103→    #[serde(rename = "browser_download_url")]
   104→    download_url: String,
   105→    size: u64,
   106→    state: String,
   107→}
   108→
   109→/// GitHub release information from API.
   110→#[derive(Debug, Deserialize)]
   111→struct GitHubRelease {
   112→    #[serde(rename = "tag_name")]
   113→    tag_name: String,
   114→    assets: Vec<GitHubAsset>,
   115→}
   116→
   117→/// Check for available updates from GitHub releases.
   118→///
   119→/// # Arguments
   120→///
   121→/// * `current_version` - Current version string (e.g., "0.1.9")
   122→///
   123→/// # Returns
   124→///
   125→/// - `UpdateStatus::UpToDate` if already on latest version
   126→/// - `UpdateStatus::Available` with download details if update available
   127→/// - `ForgeError` on network or parsing errors
   128→pub async fn check_for_update(current_version: &str) -> crate::Result<UpdateStatus> {
   129→    info!("Checking for updates (current: {})", current_version);
   130→
   131→    let client = reqwest::Client::builder()
   132→        .timeout(Duration::from_secs(API_TIMEOUT_SECS))
   133→        .user_agent(USER_AGENT)
   134→        .build()
   135→        .map_err(|e| ForgeError::UpdateCheck {
   136→            message: format!("Failed to create HTTP client: {}", e),
   137→        })?;
   138→
   139→    let response = client
   140→        .get(GITHUB_RELEASES_API)
   141→        .send()
   142→        .await
   143→        .map_err(|e| ForgeError::UpdateCheck {
   144→            message: format!("Failed to fetch releases: {}", e),
   145→        })?;
   146→
   147→    if !response.status().is_success() {
   148→        return Err(ForgeError::UpdateCheck {
   149→            message: format!("GitHub API returned status {}", response.status()),
   150→        });
   151→    }
   152→
   153→    let release: GitHubRelease = response
   154→        .json()
   155→        .await
   156→        .map_err(|e| ForgeError::UpdateCheck {
   157→            message: format!("Failed to parse release response: {}", e),
   158→        })?;
   159→
   160→    // Parse version from tag (e.g., "v0.1.9" -> "0.1.9")
   161→    let latest_version = release.tag_name.strip_prefix('v').unwrap_or(&release.tag_name);
   162→
   163→    info!("Latest version: {}", latest_version);
   164→
   165→    // Compare versions using semver
   166→    if !is_newer_version(current_version, latest_version)? {
   167→        info!("Already running latest version");
   168→        return Ok(UpdateStatus::UpToDate);
   169→    }
   170→
   171→    // Find the appropriate asset for this platform
   172→    let asset_name = get_asset_name_for_platform();
   173→    let asset = release
   174→        .assets
   175→        .iter()
   176→        .find(|a| a.name == asset_name && a.state == "uploaded")
   177→        .ok_or_else(|| ForgeError::UpdateAssetNotFound {
   178→            platform: asset_name.to_string(),
   179→        })?;
   180→
   181→    info!(
   182→        "Update available: {} -> {} ({} bytes)",
   183→        current_version, latest_version, asset.size
   184→    );
   185→
   186→    Ok(UpdateStatus::Available {
   187→        current: current_version.to_string(),
   188→        latest: latest_version.to_string(),
   189→        download_url: asset.download_url.clone(),
   190→        asset_size: asset.size,
   191→    })
   192→}
   193→
   194→/// Perform the self-update: download and atomic swap.
   195→///
   196→/// # Arguments
   197→///
   198→/// * `download_url` - URL to download the binary from
   199→/// * `expected_size` - Expected size of the download in bytes
   200→/// * `progress_tx` - Optional channel to send progress updates
   201→///
   202→/// # Returns
   203→///
   204→/// - `UpdateResult::Success` on successful update
   205→/// - `UpdateResult::Failed` with error message on failure
   206→pub async fn perform_update(
   207→    download_url: &str,
   208→    expected_size: u64,
   209→    progress_tx: Option<Sender<DownloadProgress>>,
   210→) -> crate::Result<UpdateResult> {
   211→    info!("Starting update download from {}", download_url);
   212→
   213→    // Get current executable path
   214→    let current_exe = env::current_exe().map_err(|e| ForgeError::UpdateInstall {
   215→        message: format!("Failed to get current executable path: {}", e),
   216→    })?;
   217→
   218→    // Download to a staging file
   219→    let staging_file = get_staging_path(&current_exe)?;
   220→
   221→    info!("Downloading to staging file: {:?}", staging_file);
   222→
   223→    // Download the new binary
   224→    download_file(download_url, &staging_file, expected_size, progress_tx).await?;
   225→
   226→    // Verify the downloaded file is a valid executable
   227→    verify_binary(&staging_file)?;
   228→
   229→    info!("Update download complete! Binary staged at {:?}", staging_file);
   230→
   231→    Ok(UpdateResult::Success {
   232→        old_version: env!("CARGO_PKG_VERSION").to_string(),
   233→        new_version: "latest".to_string(), // We don't have this info here anymore
   234→    })
   235→}
   236→
   237→/// Restart the process using the newly downloaded binary.
   238→///
   239→/// This function performs the following steps:
   240→/// 1. Gracefully shutdown current process (caller's responsibility)
   241→/// 2. Exec the new binary from staging location
   242→/// 3. New process will rename itself to the final location
   243→///
   244→/// This function DOES NOT RETURN on success - it replaces the current process.
   245→/// On error, it returns a ForgeError.
   246→pub fn restart_with_new_binary() -> crate::Result<()> {
   247→    info!("Initiating restart with new binary");
   248→
   249→    // Get current executable path
   250→    let current_exe = env::current_exe().map_err(|e| ForgeError::UpdateInstall {
   251→        message: format!("Failed to get current executable path: {}", e),
   252→    })?;
   253→
   254→    // Get staging path
   255→    let staging_file = get_staging_path(&current_exe)?;
   256→
   257→    // Verify staging file exists
   258→    if !staging_file.exists() {
   259→        return Err(ForgeError::UpdateInstall {
   260→            message: format!("Staging file not found at {:?}", staging_file),
   261→        });
   262→    }
   263→
   264→    info!("Staging file found at {:?}", staging_file);
   265→
   266→    // Verify the staging file is executable
   267→    verify_binary(&staging_file)?;
   268→
   269→    // Get the final install path (e.g., ~/.cargo/bin/forge)
   270→    let install_path = get_install_path(&current_exe)?;
   271→
   272→    info!(
   273→        "Will exec staging binary and install to {:?}",
   274→        install_path
   275→    );
   276→
   277→    // Prepare arguments for exec
   278→    // Pass special environment variable to signal the new process to rename itself
   279→    let mut cmd = std::process::Command::new(&staging_file);
   280→    cmd.env("FORGE_INSTALL_PATH", &install_path);
   281→    cmd.env("FORGE_STAGING_PATH", &staging_file);
   282→    cmd.env("FORGE_AUTO_RESTART", "1");
   283→
   284→    // Preserve current args
   285→    let args: Vec<String> = env::args().skip(1).collect();
   286→    cmd.args(&args);
   287→
   288→    info!(
   289→        "Execing new binary: {:?} with args: {:?}",
   290→        staging_file, args
   291→    );
   292→
   293→    // Replace current process with new binary using exec
   294→    // On Unix, use exec syscall to replace the process
   295→    exec_binary(&staging_file, &args)?;
   296→
   297→    // This line should never be reached if exec succeeds
   298→    unreachable!("exec() returned, which should never happen");
   299→}
   300→
   301→/// Check if this is a freshly exec'd process that needs to install itself.
   302→///
   303→/// Returns the install path if this process should rename itself, None otherwise.
   304→pub fn check_and_perform_self_install() -> crate::Result<Option<PathBuf>> {
   305→    // Check if we were exec'd with install instructions
   306→    if env::var("FORGE_AUTO_RESTART").is_ok() {
   307→        info!("Detected auto-restart environment - performing self-install");
   308→
   309→        let install_path_str = env::var("FORGE_INSTALL_PATH").map_err(|_| {
   310→            ForgeError::UpdateInstall {
   311→                message: "FORGE_INSTALL_PATH not set".to_string(),
   312→            }
   313→        })?;
   314→        let install_path = PathBuf::from(install_path_str);
   315→
   316→        let staging_path_str = env::var("FORGE_STAGING_PATH").map_err(|_| {
   317→            ForgeError::UpdateInstall {
   318→                message: "FORGE_STAGING_PATH not set".to_string(),
   319→            }
   320→        })?;
   321→        let staging_path = PathBuf::from(staging_path_str);
   322→
   323→        info!(
   324→            "Installing from {:?} to {:?}",
   325→            staging_path, install_path
   326→        );
   327→
   328→        // Create backup of old binary
   329→        let backup_path = install_path.with_extension("old");
   330→        if install_path.exists() {
   331→            info!("Backing up old binary to {:?}", backup_path);
   332→            if backup_path.exists() {
   333→                fs::remove_file(&backup_path).map_err(|e| ForgeError::UpdateInstall {
   334→                    message: format!("Failed to remove old backup: {}", e),
   335→                })?;
   336→            }
   337→            fs::rename(&install_path, &backup_path).map_err(|e| ForgeError::UpdateInstall {
   338→                message: format!("Failed to backup old binary: {}", e),
   339→            })?;
   340→        }
   341→
   342→        // Move staging binary to install location
   343→        fs::rename(&staging_path, &install_path).map_err(|e| {
   344→            // Try to restore backup on failure
   345→            if backup_path.exists() {
   346→                let _ = fs::rename(&backup_path, &install_path);
   347→            }
   348→            ForgeError::UpdateInstall {
   349→                message: format!("Failed to install new binary: {}", e),
   350→            }
   351→        })?;
   352→
   353→        // Set executable permissions
   354→        fs::set_permissions(&install_path, fs::Permissions::from_mode(0o755)).map_err(|e| {
   355→            ForgeError::UpdateInstall {
   356→                message: format!("Failed to set executable permissions: {}", e),
   357→            }
   358→        })?;
   359→
   360→        // Clean up environment variables
   361→        // SAFETY: These environment variables are only used during the update process
   362→        // and are safe to remove as we're done with them. No other threads should be
   363→        // accessing them during this cleanup phase.
   364→        unsafe {
   365→            env::remove_var("FORGE_AUTO_RESTART");
   366→            env::remove_var("FORGE_INSTALL_PATH");
   367→            env::remove_var("FORGE_STAGING_PATH");
   368→        }
   369→
   370→        // Save the new version to ~/.forge/version
   371→        let current_version = env!("CARGO_PKG_VERSION");
   372→        if let Err(e) = save_current_version(current_version) {
   373→            warn!("Failed to save version file: {}", e);
   374→            // Don't fail the update just because version tracking failed
   375→        }
   376→
   377→        info!("Self-install complete! Running from {:?}", install_path);
   378→
   379→        Ok(Some(install_path))
   380→    } else {
   381→        Ok(None)
   382→    }
   383→}
   384→
   385→/// Get the staging path for the downloaded binary.
   386→fn get_staging_path(_current_exe: &Path) -> crate::Result<PathBuf> {
   387→    let temp_dir = std::env::temp_dir();
   388→    let staging_file = temp_dir.join(format!("forge-update-{}", std::process::id()));
   389→    Ok(staging_file)
   390→}
   391→
   392→/// Get the final install path for the binary.
   393→///
   394→/// Determines the canonical install location (e.g., ~/.cargo/bin/forge).
   395→fn get_install_path(current_exe: &Path) -> crate::Result<PathBuf> {
   396→    // Try to determine if we're running from ~/.cargo/bin
   397→    if let Some(home) = env::var_os("HOME") {
   398→        let cargo_bin = PathBuf::from(home).join(".cargo").join("bin").join("forge");
   399→        if cargo_bin.exists() || current_exe == cargo_bin {
   400→            return Ok(cargo_bin);
   401→        }
   402→    }
   403→
   404→    // Fall back to current executable location
   405→    Ok(current_exe.to_path_buf())
   406→}
