   408→/// Execute a binary, replacing the current process (Unix-only).
   409→///
   410→/// This uses the `exec` family of syscalls to replace the current process
   411→/// with the new binary. This function does not return on success.
   412→#[cfg(unix)]
   413→fn exec_binary(path: &Path, args: &[String]) -> crate::Result<()> {
   414→    use std::ffi::CString;
   415→    use std::os::unix::ffi::OsStrExt;
   416→
   417→    // Convert path to CString
   418→    let path_cstring = CString::new(path.as_os_str().as_bytes()).map_err(|e| {
   419→        ForgeError::UpdateInstall {
   420→            message: format!("Failed to convert path to CString: {}", e),
   421→        }
   422→    })?;
   423→
   424→    // Convert args to CString array
   425→    let mut c_args: Vec<CString> = vec![path_cstring.clone()];
   426→    for arg in args {
   427→        let c_arg = CString::new(arg.as_bytes()).map_err(|e| ForgeError::UpdateInstall {
   428→            message: format!("Failed to convert arg to CString: {}", e),
   429→        })?;
   430→        c_args.push(c_arg);
   431→    }
   432→
   433→    // Convert to raw pointers for execv
   434→    let mut c_arg_ptrs: Vec<*const i8> = c_args.iter().map(|s| s.as_ptr()).collect();
   435→    c_arg_ptrs.push(std::ptr::null()); // NULL-terminated array
   436→
   437→    // Call execv - this replaces the current process
   438→    unsafe {
   439→        libc::execv(path_cstring.as_ptr(), c_arg_ptrs.as_ptr());
   440→    }
   441→
   442→    // If we get here, exec failed
   443→    let errno = std::io::Error::last_os_error();
   444→    Err(ForgeError::UpdateInstall {
   445→        message: format!("execv() failed: {}", errno),
   446→    })
   447→}
   448→
   449→/// Non-Unix platforms are not supported for self-update restart.
   450→#[cfg(not(unix))]
   451→fn exec_binary(_path: &Path, _args: &[String]) -> crate::Result<()> {
   452→    Err(ForgeError::UpdateInstall {
   453→        message: "Self-update restart not supported on this platform".to_string(),
   454→    })
   455→}
