   457→/// Download a file with progress reporting.
   458→async fn download_file(
   459→    url: &str,
   460→    dest: &Path,
   461→    expected_size: u64,
   462→    progress_tx: Option<Sender<DownloadProgress>>,
   463→) -> crate::Result<()> {
   464→    let client = reqwest::Client::builder()
   465→        .timeout(Duration::from_secs(DOWNLOAD_TIMEOUT_SECS))
   466→        .user_agent(USER_AGENT)
   467→        .build()
   468→        .map_err(|e| ForgeError::UpdateDownload {
   469→            message: format!("Failed to create HTTP client: {}", e),
   470→        })?;
   471→
   472→    let mut response = client
   473→        .get(url)
   474→        .send()
   475→        .await
   476→        .map_err(|e| ForgeError::UpdateDownload {
   477→            message: format!("Failed to start download: {}", e),
   478→        })?;
   479→
   480→    if !response.status().is_success() {
   481→        return Err(ForgeError::UpdateDownload {
   482→            message: format!("Download failed with status {}", response.status()),
   483→        });
   484→    }
   485→
   486→    // Create the destination file
   487→    let mut file = fs::File::create(dest).map_err(|e| ForgeError::UpdateDownload {
   488→        message: format!("Failed to create temp file: {}", e),
   489→    })?;
   490→
   491→    // Download in chunks with progress reporting
   492→    let mut downloaded: u64 = 0;
   493→
   494→    loop {
   495→        let chunk = response
   496→            .chunk()
   497→            .await
   498→            .map_err(|e| ForgeError::UpdateDownload {
   499→                message: format!("Download interrupted: {}", e),
   500→            })?;
   501→
   502→        match chunk {
   503→            Some(chunk) => {
   504→                file.write_all(&chunk).map_err(|e| ForgeError::UpdateDownload {
   505→                    message: format!("Failed to write to temp file: {}", e),
   506→                })?;
   507→
   508→                downloaded += chunk.len() as u64;
   509→
   510→                // Report progress
   511→                if let Some(ref tx) = progress_tx {
   512→                    let percent = if expected_size > 0 {
   513→                        ((downloaded as f64 / expected_size as f64) * 100.0) as u8
   514→                    } else {
   515→                        0
   516→                    };
   517→
   518→                    let progress = DownloadProgress {
   519→                        downloaded,
   520→                        total: expected_size,
   521→                        percent: percent.min(100),
   522→                    };
   523→
   524→                    // Send progress (ignore errors if receiver is gone)
   525→                    let _ = tx.send(progress);
   526→                }
   527→            }
   528→            None => break, // End of stream
   529→        }
   530→    }
   531→
   532→    // Verify download size
   533→    if expected_size > 0 && downloaded != expected_size {
   534→        return Err(ForgeError::UpdateDownload {
   535→            message: format!(
   536→                "Download size mismatch: expected {}, got {}",
   537→                expected_size, downloaded
   538→            ),
   539→        });
   540→    }
   541→
   542→    info!("Download complete: {} bytes", downloaded);
   543→    Ok(())
   544→}
   545→
   546→/// Verify the downloaded binary is a valid executable.
   547→fn verify_binary(path: &Path) -> crate::Result<()> {
   548→    // Check file exists and has content
   549→    let metadata = fs::metadata(path).map_err(|e| ForgeError::UpdateVerification {
   550→        message: format!("Failed to read downloaded file: {}", e),
   551→    })?;
   552→
   553→    if metadata.len() == 0 {
   554→        return Err(ForgeError::UpdateVerification {
   555→            message: "Downloaded file is empty".to_string(),
   556→        });
   557→    }
   558→
   559→    // Check ELF magic bytes (Linux executable)
   560→    let mut file = fs::File::open(path).map_err(|e| ForgeError::UpdateVerification {
   561→        message: format!("Failed to open downloaded file: {}", e),
   562→    })?;
   563→
   564→    let mut magic = [0u8; 4];
   565→    Read::read_exact(&mut file, &mut magic).map_err(|e| ForgeError::UpdateVerification {
   566→        message: format!("Failed to read file header: {}", e),
   567→    })?;
   568→
   569→    // ELF magic: 0x7f 'E' 'L' 'F'
   570→    if magic != [0x7f, 0x45, 0x4c, 0x46] {
   571→        return Err(ForgeError::UpdateVerification {
   572→            message: "Downloaded file is not a valid ELF binary".to_string(),
   573→        });
   574→    }
   575→
   576→    info!("Binary verification passed (valid ELF)");
   577→    Ok(())
   578→}
