   598→/// Compare two version strings to determine if the second is newer.
   599→///
   600→/// Uses semantic versioning comparison (major.minor.patch).
   601→fn is_newer_version(current: &str, latest: &str) -> crate::Result<bool> {
   602→    let current_parts: Vec<u32> = current
   603→        .split('.')
   604→        .filter_map(|s| s.parse().ok())
   605→        .collect();
   606→
   607→    let latest_parts: Vec<u32> = latest
   608→        .split('.')
   609→        .filter_map(|s| s.parse().ok())
   610→        .collect();
   611→
   612→    if current_parts.is_empty() || latest_parts.is_empty() {
   613→        return Err(ForgeError::UpdateCheck {
   614→            message: format!("Invalid version format: {} or {}", current, latest),
   615→        });
   616→    }
   617→
   618→    // Pad to 3 components (major.minor.patch)
   619→    let current_parts = pad_version(&current_parts);
   620→    let latest_parts = pad_version(&latest_parts);
   621→
   622→    // Compare major.minor.patch
   623→    Ok(latest_parts > current_parts)
   624→}
   625→
   626→/// Pad version components to 3 elements.
   627→fn pad_version(parts: &[u32]) -> [u32; 3] {
   628→    let mut result = [0u32; 3];
   629→    for (i, &part) in parts.iter().enumerate().take(3) {
   630→        result[i] = part;
   631→    }
   632→    result
   633→}
