   717→
   718→/// Rollback result indicating what happened.
   719→#[derive(Debug, Clone, PartialEq)]
   720→pub enum RollbackResult {
   721→    /// Successfully rolled back from backup
   722→    RolledBack {
   723→        /// Version that was rolled back from
   724→        failed_version: String,
   725→        /// Version rolled back to (if known)
   726→        restored_version: Option<String>,
   727→    },
   728→    /// No rollback needed (no crash detected)
   729→    NotNeeded,
   730→    /// Rollback failed (backup not found or other error)
   731→    Failed(String),
   732→}
   733→
   734→/// Attempt to rollback to the .old backup if startup crashed.
   735→///
   736→/// This should be called at the very beginning of main() before any other initialization.
   737→///
   738→/// Returns:
   739→/// - `RollbackResult::RolledBack` if rollback was performed
   740→/// - `RollbackResult::NotNeeded` if no crash was detected
   741→/// - `RollbackResult::Failed` if rollback was needed but failed
   742→pub fn check_and_rollback() -> RollbackResult {
   743→    // Check if previous startup crashed
   744→    if !did_previous_startup_crash() {
   745→        return RollbackResult::NotNeeded;
   746→    }
   747→
   748→    warn!("Detected crash on previous startup, attempting rollback...");
   749→
   750→    // Get current executable path
   751→    let current_exe = match env::current_exe() {
   752→        Ok(path) => path,
   753→        Err(e) => {
   754→            error!("Failed to get current executable path: {}", e);
   755→            return RollbackResult::Failed(format!("Failed to get executable path: {}", e));
   756→        }
   757→    };
   758→
   759→    let backup_path = current_exe.with_extension("old");
   760→
   761→    // Check if backup exists
   762→    if !backup_path.exists() {
